(() => {
  const data = [
    { id: 'fruit', data: { label: 'Fruit' }, children: [
      { id: 'apple', data: { label: 'Apple' } },
      { id: 'banana', data: { label: 'Banana' } }
    ]}
  ];
  const [sel, setSel] = React.useState<string[]>([]);
  return (<Tree nodes={data} getLabel={(n) => n.label} defaultExpanded={['fruit']} selected={sel} onSelectionChange={setSel} variant='chevron' />);
})()

(() => {
  const data = [
    { id: 'a', data: { label: 'Alpha' } },
    { id: 'b', data: { label: 'Bravo' } },
    { id: 'c', data: { label: 'Charlie' } }
  ];
  const [sel, setSel] = React.useState(['a']);
  return (<Tree nodes={data} getLabel={(n) => n.label} selectionMode='multiple' selected={sel} onSelectionChange={setSel} variant='list' />);
})()

(() => {
  const files = [
    { id: 'src', data: { label: 'src' }, children: [
      { id: 'index.ts', data: { label: 'index.ts' } }
    ]}
  ];
  return (<Tree nodes={files} getLabel={(n) => n.label} defaultExpanded={['src']} variant='files' />);
})()
